import './App.css';

function Img_cabecalho(){
  return (
    <img src= 'https://www.google.com/imgres?q=playstation%20logo&imgurl=https%3A%2F%2Fdownload.logo.wine%2Flogo%2FPlayStation%2FPlayStation-Logo.wine.png&imgrefurl=https%3A%2F%2Fwww.logo.wine%2Flogo%2FPlayStation&docid=oo6TN67S2NxGtM&tbnid=LO-hCVt7PqrpNM&vet=12ahUKEwj_i7my1biUAxXDppUCHdiRHSQQnPAOegQIGRAB..i&w=3000&h=2000&hcb=2&ved=2ahUKEwj_i7my1biUAxXDppUCHdiRHSQQnPAOegQIGRAB'
      alt='playstation'
      className='Logo'
      />
  )
}
function Titulo(){
  return <h1>Playstation</h1>
}
function Apresentacao(){
  return <h2>Jogar Não Tem Limites</h2>
}
function Titulo_card1(){
  return <h2>Essencial</h2>,
  <h3>Jogos mensais, modo multijogador e muito mais</h3>
}
function Card1_info(){
  return <h2>✅ Jogos mensais</h2>, <h2>✅ Modo multijogador online</h2>,
  <h2>✅ Descontos exclusivos</h2>
}
function Botao_card1(){
  return <button> Selecionar </button>
}
function Titulo_card2(){
  return <h2>Extra</h2>,
  <h3>Descubra centenas de jogos</h3>
}
function Card2_info(){
  return <h2>✅ Jogos mensais</h2>, <h2>✅ Modo multijogador online</h2>,
  <h2>✅ Descontos exclusivos</h2>, <h2>✅ Catálogo de jogos</h2>,
  <h2>✅ Ubisoft</h2>
}
